public:
    bool canConvertString(string s, string t, int k) {
        int n = s.size();
        for (int i = 0; i < n; ++i) {
            int diff = (t[i] - s[i] + 26) % 26;
            if (diff > k) return false;
            k -= diff;
        }
        return true;
    }
};
